{%- if item.text -%}
{%- assign GroupTitle = item.text -%}
<h2>{{ GroupTitle }}</h2>
{%- endif -%}

{%- comment -%} -- Datum procedure + Uitvoerende arts -- {%- endcomment -%}
{%- assign datum_answer = datum_procedure.answer[0].valueDate -%}
{%- assign arts_answer = uitvoerende_arts.answer[0].valueCoding.display -%}
<div>Coloscopie uitgevoerd op {{ datum_answer | date: "%d-%m-%Y" | default: '&lt;DATUM ONTBREEKT&gt;' }}, door dr. {{ arts_answer | default: '&lt;ARTS ONTBREEKT&gt;' }}.</div>

{%- comment -%} -- Type verwijzer -- {%- endcomment -%}
{%- for answer in verwijzer.answer -%}
{%- assign verwijzer_answer = verwijzer.answer[forloop.index0] -%}
{%- assign verwijzend_ziekenhuis = verwijzer_answer | fhirpath : "item.where(linkId='01920082-2de5-7551-9a63-9fb13ba6f356')" | first -%}
{%- assign verwijzende_specialist = verwijzer_answer | fhirpath : "item.where(linkId='01920587-6761-7eed-9d24-b0bbed037d27')" | first -%}
{%- assign verwijzer_type = verwijzer_answer.valueCoding.display -%}
{%- if verwijzer_type == 'via specialist extern' -%}
<div>Patiënt verwezen {{ " " }}
{%- if verwijzend_ziekenhuis -%}
{{- verwijzend_ziekenhuis.answer[0].valueCoding.display -}}
{%- if verwijzende_specialist and verwijzende_specialist.answer[0].valueCoding.display %}{{ " " }}via {{ verwijzende_specialist.answer[0].valueCoding.display }}
{%- else %}{{ " " }}via &lt;ARTS ONTBREEKT&gt;
{%- endif -%}
{%- else -%}
via &lt;ZIEKENHUIS ONTBREEKT&gt;
{%- endif -%}.</div>
{%- endif -%}
{%- endfor -%}

{%- comment -%} -- Indicatie (includes urgentie) -- {%- endcomment -%}
{%- assign indicatie_answer = indicatie.answer | map: 'valueCoding' | map: 'display' | join: ', ' -%}
{%- assign urgentie_answer = urgentie.answer | map: 'valueCoding' | map: 'display' | join: ', ' -%}
{%- if indicatie_answer and indicatie_answer != '' -%}
<div>Indicatie: {% if urgentie_answer and urgentie_answer == 'ja' %}Urgentie, {% endif %}{{ indicatie_answer }}.</div>
{%- elsif urgentie_answer and urgentie_answer == 'ja' -%}
<div>Indicatie: urgentie.</div>
{%- endif -%}

{%- comment -%} -- Type sedatie -- {%- endcomment -%}
{%- for answer in sedatie.answer -%}
{%- assign sedatie_answer = sedatie.answer[forloop.index0] -%}
{%- assign sedatie_type = sedatie_answer.valueCoding.display -%}
{%- assign anesthesist_item = sedatie_answer | fhirpath : "item.where(linkId='0192058b-5869-7eed-9d40-f8ce1a484ae6')" | first -%}
{%- if sedatie_type == 'nee' -%}
<div>Onderzoek zonder sedatie.</div>
{%- elsif sedatie_type == 'procedurele sedatie' -%}
<div>Onderzoek onder {{ sedatie_type }}.</div>
{%- elsif sedatie_type == 'anesthesie' -%}
{%- assign anesthesist_naam = anesthesist_item.answer[0].valueCoding.display -%}
<div>Onderzoek onder {{ sedatie_type }}{%- if anesthesist_naam -%}, uitgevoerd door dr. {{ anesthesist_naam }}{%- else -%}, uitgevoerd door &lt;ANESTHESIST ONTBREEKT&gt;{%- endif -%}.</div>
{%- endif -%}
{%- endfor -%}

