{%- endif -%}

{%- comment -%} -- Problemen bij voorbereiding -- {%- endcomment -%}
{%- assign problemen_answer = problemen_bij_voorbereiding.answer | map: 'valueCoding' | map: 'display' | join: ', ' -%}
{%- if problemen_answer and problemen_answer != '' and problemen_answer != 'geen' -%}
<div>Problemen bij voorbereiding: {{ problemen_answer }}.</div>
{%- endif -%}

{%- comment -%} -- BBPS -- {%- endcomment -%}
{%- assign bbps_score = boston_bowel_preparation_scale_bbps | fhirpath : "item.where(linkId='019e63ba-c63e-7dd7-b31e-523024bc12a5').answer[0].valueDecimal" | first -%}
{%- assign darmreiniging = boston_bowel_preparation_scale_bbps | fhirpath : "item.where(linkId='019e63ba-c63e-7dd7-b31e-6592459636a2').answer[0].valueCoding.display" | first -%}
{%- if bbps_score and darmreiniging -%}
<div>BBPS: {{ bbps_score }}/9, darmreiniging {{ darmreiniging }}.</div>
{%- elsif bbps_score -%}
<div>BBPS: {{ bbps_score }}/9.</div>
{%- elsif darmreiniging -%}
<div>Darmreiniging {{ darmreiniging }}.</div>
{%- endif -%}

{%- comment -%} -- Caecum bereikt -- {%- endcomment -%}
{%- for answer in caecum_bereikt.answer -%}
{%- assign caecum_answer = caecum_bereikt.answer[forloop.index0] -%}
{%- assign caecum_bereikt_ja = caecum_answer.valueCoding.display -%}
{%- assign inspectie_ileum = caecum_answer | fhirpath : "item.where(linkId='01920aa4-39d8-7663-8dab-af2f51024969').answer[0].valueCoding.display" | first -%}
{%- assign diepst_bereikte = caecum_answer | fhirpath : "item.where(linkId='01920aa4-e0f2-7663-8db6-40f2e701f18e').answer[0].valueCoding.display" | first -%}
{%- assign oorzaak = caecum_answer | fhirpath : "item.where(linkId='01920aa6-e94a-7663-8dc2-7663161063aa').answer[0].valueCoding.display" | first -%}
{%- if caecum_bereikt_ja == 'ja' and inspectie_ileum == 'nee' -%}
<div>Insertiediepte: Caecum.</div>
{%- elsif caecum_bereikt_ja == 'ja' and inspectie_ileum == 'ja' -%}
<div>Insertiediepte: Terminaal ileum.</div>
{%- elsif caecum_bereikt_ja == 'nee' -%}
<div>Insertiediepte: {{ diepst_bereikte | default: '&lt;DIEPSTE PUNT ONTBREEKT&gt;' }}.</div>
<div>Caecum niet bereikt omwille van {{ oorzaak | default: '&lt;OORZAAK ONTBREEKT&gt;' }}.</div>
{%- endif -%}
{%- endfor -%}

{%- comment -%} -- Terugtrektijd -- {%- endcomment -%}
{%- assign terugtrektijd_answer = terugtrektijd_hh_mm_ss.answer[0].valueTime -%}
{%- if terugtrektijd_answer -%}
<div>Terugtrektijd hh:mm:ss: {{ terugtrektijd_answer }}.</div>
{%- endif -%}

{%- comment -%} -- Retrovisie ascendens -- {%- endcomment -%}
{%- assign retrovisie_asc_answer = retrovisie_ascendens.answer[0].valueCoding.display -%}
{%- assign bevindingen_asc_answer = wat_werd_gezien_in_retrovisie_ascendens.answer[0].valueString -%}
{%- if retrovisie_asc_answer -%}
<div>Retrovisie ascendens: {{ retrovisie_asc_answer }}{%- if bevindingen_asc_answer -%}, {{ bevindingen_asc_answer }}{%- endif -%}.</div>
{%- endif -%}

{%- comment -%} -- Retrovisie rectum -- {%- endcomment -%}
{%- assign retrovisie_rect_answer = retrovisie_rectum.answer[0].valueCoding.display -%}
{%- assign bevindingen_rect_answer = wat_werd_gezien_in_retrovisie_rectum.answer[0].valueString -%}
{%- if retrovisie_rect_answer -%}
<div>Retrovisie rectum: {{ retrovisie_rect_answer }}{%- if bevindingen_rect_answer -%}, {{ bevindingen_rect_answer }}{%- endif -%}.</div>
{%- endif -%}

{%- comment -%} -- CADe/CADx (empty templates in original) -- {%- endcomment -%}

{%- comment -%} === SECTION: Poliepen === {%- endcomment -%}
{%- assign item = Poliepen-item -%}
{%- assign poliep_aanwezig = item | fhirpath : "item.where(linkId='0196f6f2-c567-788e-8dbf-873772f0b24c')" | first -%}
{%- assign poliepen = item | fhirpath : "item.where(linkId='019541c0-b2ea-7ffd-a95a-38cbe7e9d713')" -%}
{%- assign poliep_aanwezig_answer = poliep_aanwezig.answer[0].valueCoding.display -%}

{%- if poliep_aanwezig_answer == 'nee' or poliepen.size > 0 -%}
{%- if item.text -%}
<h2>{{ item.text }}</h2>
{%- endif -%}
{%- endif -%}

{%- if poliep_aanwezig_answer == 'nee' -%}
<div>Geen poliepen aanwezig.</div>
{%- endif -%}

{%- for poliep in poliepen -%}
