{%- assign mucosaal = poliep | fhirpath : "item.where(linkId='01920abd-88a7-7663-8e4b-2639aef68153').answer[0].valueCoding.display" | first -%}
{%- assign wasp = poliep | fhirpath : "item.where(linkId='019d9690-a1fd-7dd5-b316-d8ff7d3f45e7').answer[0].valueCoding.display" | first -%}
{%- assign jnet = poliep | fhirpath : "item.where(linkId='01920abe-abc6-7663-8e55-e52634c1ea9e').answer[0].valueCoding.display" | first -%}
{%- assign resectie_item = poliep | fhirpath : "item.where(linkId='01920abf-dc00-7663-8e65-afb7fbb5fabd')" | first -%}
{%- assign first_resectie = resectie_item.answer[0].valueCoding.display -%}

